/**
 * Calculates the estimated heating cost during a severe weather event.
 * Inputs:
 * - homeSquareFootage: Number, square footage of the heated area of the home.
 * - effectiveRValue: Number, overall effective R-value of the home's thermal envelope.
 * - targetIndoorTemp: Number, desired indoor temperature in °F.
 * - expectedOutdoorTemp: Number, lowest expected outdoor temperature in °F.
 * - stormDurationHours: Number, duration of the severe weather event in hours.
 * - heatingFuelType: String, type of fuel used (Natural Gas, Electricity, Heating Oil, Propane).
 * - fuelCostPerUnit: Number, cost per unit of fuel ($/therm, $/kWh, $/gallon).
 * - furnaceEfficiency: Number, efficiency of the heating system in percentage (AFUE for gas/oil, COP for heat pumps where 100% = 1 COP).
 */

function calculateHeatingCost({
  homeSquareFootage,
  effectiveRValue,
  targetIndoorTemp,
  expectedOutdoorTemp,
  stormDurationHours,
  heatingFuelType,
  fuelCostPerUnit,
  furnaceEfficiency
}) {
  // Input validation and sensible defaults/caps
  homeSquareFootage = Math.max(50, homeSquareFootage || 0);
  effectiveRValue = Math.max(5, Math.min(60, effectiveRValue || 5)); // Cap R-value between 5 and 60
  targetIndoorTemp = Math.max(50, Math.min(80, targetIndoorTemp || 68)); // Cap indoor temp
  expectedOutdoorTemp = Math.min(targetIndoorTemp - 5, expectedOutdoorTemp || 0); // Ensure outdoor is less than indoor, cap for extreme cold
  stormDurationHours = Math.max(1, stormDurationHours || 24);
  fuelCostPerUnit = Math.max(0.001, fuelCostPerUnit || 0.1);
  furnaceEfficiency = Math.max(1, Math.min(700, furnaceEfficiency || 90)); // Cap efficiency from 1% to 700% (for very high COP heat pumps)

  // Step 1: Calculate Temperature Difference (Delta T)
  const deltaT = targetIndoorTemp - expectedOutdoorTemp;

  // If outdoor temp is higher or equal to target indoor temp, no heating is needed.
  if (deltaT <= 0) {
    return {
      estimatedTotalCost: 0,
      totalEnergyConsumed: 0,
      hourlyHeatingCost: 0
    };
  }

  // Step 2: Estimate Hourly Heat Loss (BTU/hour)
  // A simplified Heat Loss Factor (HLF) in BTU per sqft per hour per degree F.
  // This factor implicitly accounts for an 'average' home's walls, windows, and air leakage.
  // We will adjust it based on the user's provided effective R-value.
  // Baseline HLF for an average home (e.g., R-20 equivalent, roughly 0.015 BTU/sqft/hr/°F)
  const baselineHLF_BTU_per_sqft_per_hr_per_degF = 0.015; 

  // Adjust HLF: Lower R-value means higher heat loss, higher R-value means lower heat loss.
  // The '20' here represents a reference R-value for the baseline HLF.
  const adjustedHLF = baselineHLF_BTU_per_sqft_per_hr_per_degF * (20 / effectiveRValue);

  const hourlyHeatLoss_BTU = homeSquareFootage * deltaT * adjustedHLF;

  // Step 3: Calculate Total Heat Needed (BTU) over the storm duration
  const totalHeatNeeded_BTU = hourlyHeatLoss_BTU * stormDurationHours;

  // Step 4: Account for Heating System Efficiency
  // Convert furnace efficiency to a decimal. For COP values (e.g., 300% efficiency = COP of 3), divide by 100.
  const efficiencyDecimal = furnaceEfficiency / 100;
  const effectiveHeatNeeded_BTU = totalHeatNeeded_BTU / efficiencyDecimal;

  // Step 5: Convert BTU to Fuel-Specific Units and Calculate Cost
  let energyUnitsConsumed = 0;
  let outputUnitLabel = "";
  const BTU_per_therm = 100000;
  const BTU_per_kWh = 3412;
  const BTU_per_gallon_oil = 138000;
  const BTU_per_gallon_propane = 91500;

  switch (heatingFuelType) {
    case "Natural Gas":
      energyUnitsConsumed = effectiveHeatNeeded_BTU / BTU_per_therm;
      outputUnitLabel = "therms";
      break;
    case "Electricity":
      energyUnitsConsumed = effectiveHeatNeeded_BTU / BTU_per_kWh;
      outputUnitLabel = "kWh";
      break;
    case "Heating Oil":
      energyUnitsConsumed = effectiveHeatNeeded_BTU / BTU_per_gallon_oil;
      outputUnitLabel = "gallons";
      break;
    case "Propane":
      energyUnitsConsumed = effectiveHeatNeeded_BTU / BTU_per_gallon_propane;
      outputUnitLabel = "gallons";
      break;
    default:
      return {
        estimatedTotalCost: 0,
        totalEnergyConsumed: 0,
        hourlyHeatingCost: 0,
        error: "Invalid heating fuel type provided."
      };
  }

  const estimatedTotalCost = energyUnitsConsumed * fuelCostPerUnit;
  const hourlyHeatingCost = estimatedTotalCost / stormDurationHours;

  return {
    estimatedTotalCost: estimatedTotalCost,
    totalEnergyConsumed: energyUnitsConsumed,
    hourlyHeatingCost: hourlyHeatingCost,
    _unitForTotalEnergyConsumed: outputUnitLabel // Internal field for output unit display
  };
}
